// Acknowledge Z-API immediately
const body = $input.first().json.body;
const messageId = body.message?.messageId ?? body.messageId;
const phone = body.phone;
const msgType = body.message?.imageMessage ? 'image' : body.type;

if (!messageId || !phone) {
  throw new Error('Missing messageId or phone in Z-API payload');
}
if (msgType !== 'image' && !body.message?.imageMessage) {
  // Not an image message — silently ignore
  return [];
}

const imageUrl = body.message?.imageMessage?.url;
if (!imageUrl) throw new Error('No image URL in payload');

return [{ json: { messageId, phone, imageUrl, chatName: body.chatName ?? '', timestamp: body.momment ?? Date.now() } }];

// If the Sheets lookup returned a row with this messageId, it's a duplicate — stop.
const existing = $input.first().json;
if (existing.jobId) {
  // Row found — duplicate
  return [];
}
// Pass through
return $input.all();

// Make Drive file public and build the public URL
const fileId = $input.first().json.id;
return [{ json: { fileId, publicUrl: `https://drive.google.com/uc?id=${fileId}&export=download` } }];

// Accumulate all processed photo URLs from the batch loop
// This runs after SplitInBatches finishes all items
const allUrls = $input.all().map(item => item.json.publicUrl);
const firstItem = $('Code: Extract & Validate').first().json;

return [{
  json: {
    messageId: firstItem.messageId,
    phone: firstItem.phone,
    chatName: firstItem.chatName,
    photoUrls: allUrls,
    timestamp: firstItem.timestamp
  }
}];

