parameters.jsCode:
const raw = $input.first().json.candidates?.[0]?.content?.parts?.[0]?.text ?? '{}';
let analysis;
try {
  // Strip markdown code fences if present
  const cleaned = raw.replace(/^```json\n?|```$/g, '').trim();
  analysis = JSON.parse(cleaned);
} catch {
  throw new Error('Gemini returned invalid JSON: ' + raw.substring(0, 200));
}

const acc = $('Code: Accumulate Photo URLs').first().json;

// Reorder photos by Gemini's recommended sort order
const sortOrder = analysis.photoSortOrder ?? acc.photoUrls.map((_, i) => i);
const sortedUrls = sortOrder.map((i) => acc.photoUrls[i]).filter(Boolean);

return [{
  json: {
    jobId: acc.messageId,
    phone: acc.phone,
    chatName: acc.chatName,
    partId: analysis.partId ?? '',
    title: (analysis.title ?? 'Peça Automotiva Usada').substring(0, 60),
    description: analysis.description ?? '',
    suggestedPrice: analysis.suggestedPrice ?? 0,
    mlCategoryId: analysis.mlCategoryId ?? '',
    color: analysis.color ?? '',
    vehicleCompat: JSON.stringify(analysis.vehicleCompatibilities ?? []),
    photoUrls: JSON.stringify(sortedUrls),
    createdAt: new Date().toISOString(),
    rawGeminiResponse: raw
  }
}];

const payload = $input.first().json.body ?? $input.first().json;
const action = payload.action;
const price = parseFloat(payload.price ?? 0);
const jobId = payload.jobId;

if (action === 'reject') {
  return [{ json: { action: 'reject', price: 0, jobId, _stop: true } }];
}
if (!price || price <= 0) {
  throw new Error('Invalid price received in resume payload');
}
return [{ json: { action: 'approve', price, jobId, _stop: false } }];

